+fn user_texts_in_order(messages: &[Message]) -> Vec<String> {
+    messages
+        .iter()
+        .filter_map(|message| match message {
+            Message::User(user) => match &user.content {
+                UserContent::Text(text) => Some(text.clone()),
+                UserContent::Blocks(_) => None,
+            },
+            _ => None,
+        })
+        .collect()
+}
